import edu.ucr.cs.bdlab.beast.indexing.IndexHelper.{Fixed, NumPartitions}
import edu.ucr.cs.bdlab.beast.indexing.{IndexHelper, RSGrovePartitioner}

val originalCount = featuresRDD.count()
val numParts = math.max(1, featuresRDD.getNumPartitions)

// Create a disjoint partitioner which may replicate features that cross partition boundaries
val partitioner = IndexHelper.createPartitioner(
  featuresRDD, 
  classOf[RSGrovePartitioner],
  NumPartitions(Fixed, numParts), 
  _ => 1, 
  "disjoint" -> true
)

// Apply the partitioner to the features RDD
val partitionedFeatures = featuresRDD.spatialPartition(partitioner)
val newCount = partitionedFeatures.count()

// Verify that the RDD is actually partitioned
assert(partitionedFeatures.partitioner.isDefined, "Partitioned RDD must have a partitioner defined")

// Verify that no features were lost (and some may have been replicated due to disjoint=true)
assert(newCount >= originalCount, s"Partitioned count $newCount should be >= original count $originalCount due to potential replication")

println(s"__CHECK__ createPartitioner originalCount: $originalCount, newCount: $newCount, partitioner: ${partitioner.getClass.getSimpleName}")

