val eulerCountHistogram = featuresRDD.eulerHistogramCount(Array(10, 10))

// The exact methods on the returned EulerHistogram synopsis object may vary,
// but it should expose zero-argument methods returning metrics like the number 
// of buckets (100), number of features, or sum of counts.
val validTypes = Set[Class[_]](
  java.lang.Long.TYPE, java.lang.Integer.TYPE,
  classOf[java.lang.Long], classOf[java.lang.Integer]
)

val methods = eulerCountHistogram.getClass.getMethods.filter(m => 
  m.getParameterCount == 0 && validTypes.contains(m.getReturnType) && m.getName != "hashCode"
)

val values = methods.flatMap { m =>
  scala.util.Try(m.invoke(eulerCountHistogram).asInstanceOf[Number].longValue())
    .toOption
    .map(v => m.getName -> v)
}.toMap

val expectedBuckets = 10 * 10
assert(values.values.exists(v => v == expectedBuckets || v > 0), 
  s"Histogram should reflect $expectedBuckets buckets or positive counts, got: $values")

println(s"__CHECK__ eulerHistogramCount metrics: $values")

