import edu.ucr.cs.bdlab.beast._
import edu.ucr.cs.bdlab.beast.synopses.Summary

// Take a small sample to manually verify the summary statistics
val sampleFeatures = featuresRDD.take(10)
assert(sampleFeatures.nonEmpty, "featuresRDD must not be empty")

// Compute the summary on the sample
val sampleRDD = sc.parallelize(sampleFeatures)
val summary: Summary = sampleRDD.summary

// Call sumSideLength as documented
val sumSideLengths = summary.sumSideLength

assert(sumSideLengths != null, "sumSideLength array should not be null")
assert(sumSideLengths.length >= 2, "sumSideLength array should have at least 2 dimensions")

// Manually compute the expected sum of side lengths for the sample
var expectedSumX = 0.0
var expectedSumY = 0.0
for (f <- sampleFeatures) {
  val geom = f.getGeometry
  if (geom != null && !geom.isEmpty) {
    val env = geom.getEnvelopeInternal
    expectedSumX += env.getWidth
    expectedSumY += env.getHeight
  }
}

// Verify the computed summary matches the manual calculation
assert(Math.abs(sumSideLengths(0) - expectedSumX) < 1e-6, s"Expected sum X $expectedSumX but got ${sumSideLengths(0)}")
assert(Math.abs(sumSideLengths(1) - expectedSumY) < 1e-6, s"Expected sum Y $expectedSumY but got ${sumSideLengths(1)}")

println(s"__CHECK__ sumSideLength [${sumSideLengths.mkString(", ")}]")

